package market.domain;

import javax.persistence.Column;
import javax.persistence.EmbeddedId;
import javax.persistence.Entity;
import javax.persistence.FetchType;
import javax.persistence.JoinColumn;
import javax.persistence.ManyToOne;
import javax.persistence.MapsId;
import javax.persistence.Table;
import java.io.Serializable;
import java.util.Objects;

@Entity
@Table(name = "cart_item")
public class CartItem implements Serializable {
	private static final long serialVersionUID = -3995571478236070123L;

	@EmbeddedId
	private CartItemId pk = new CartItemId();

	@MapsId("cartId")
	@JoinColumn(name = "cart_id", referencedColumnName = "id")
	@ManyToOne(optional = false, fetch = FetchType.LAZY)
	private Cart cart;

	@MapsId("productId")
	@JoinColumn(name = "product_id", referencedColumnName = "id")
	@ManyToOne(optional = false, fetch = FetchType.EAGER)
	private Product product;

	@Column(name = "quantity")
	private int quantity;

	public CartItem() {
	}

	public CartItem(Cart cart, Product product, int quantity) {
		this.pk = new CartItemId(cart.getId(), product.getId());
		this.cart = cart;
		this.product = product;
		this.quantity = quantity;
	}

	public double calculateCost() {
		return quantity * product.getPrice();
	}

	public int getQuantity() {
		return quantity;
	}

	public void setQuantity(int quantity) {
		this.quantity = quantity;
	}

	public Product getProduct() {
		return product;
	}

	public void setProduct(Product product) {
		this.product = product;
		pk.setProduct(product.getId());
	}

	@Override
	public boolean equals(Object o) {
		if (this == o) {
			return true;
		}
		if (o == null || getClass() != o.getClass()) {
			return false;
		}
		CartItem that = (CartItem) o;
		return Objects.equals(pk, that.pk);
	}

	@Override
	public int hashCode() {
		return (pk != null ? pk.hashCode() : 0);
	}
}

package market.dto;

import org.springframework.hateoas.RepresentationModel;

import javax.validation.constraints.NotEmpty;
import javax.validation.constraints.Pattern;
import javax.validation.constraints.Size;
import java.util.Objects;

public class UserDTO extends RepresentationModel<UserDTO> {
	public static final String ALPHANUMERIC = "^[a-zA-Z0-9]+$";
	public static final String EMAIL_REGEX = "^[\\w-]+(\\.[\\w-]+)*@([\\w-]+\\.)+[a-zA-Z]+$";
	public static final String USER_PHONE_REGEX = "^\\+[1-9][0-9]?[\\s]*\\(?\\d{3}\\)?[-\\s]?\\d{3}[-\\s]?\\d{2}[-\\s]?\\d{2}$";
	public static final String USER_ADDRESS_REGEX = "^[^#$%^*()']*$";

	public static final String HIDDEN_PASSWORD = "hidden";

	@NotEmpty
	@Size(max = 50)
	@Pattern(regexp = EMAIL_REGEX)
	private String email;

	@Size(min = 6, max = 50)
	@Pattern(regexp = ALPHANUMERIC)
	private String password;

	@NotEmpty
	@Size(max = 50)
	@Pattern(regexp = "^[\\pL '-]+$")
	private String name;

	@NotEmpty
	@Size(max = 20)
	@Pattern(regexp = USER_PHONE_REGEX)
	private String phone;

	@NotEmpty
	@Size(max = 100)
	@Pattern(regexp = USER_ADDRESS_REGEX)
	private String address;

	public String getEmail() {
		return email;
	}

	public void setEmail(String email) {
		this.email = email;
	}

	public String getPassword() {
		return password;
	}

	public void setPassword(String password) {
		this.password = password;
	}

	public String getName() {
		return name;
	}

	public void setName(String name) {
		this.name = name;
	}

	public String getPhone() {
		return phone;
	}

	public void setPhone(String phone) {
		this.phone = phone;
	}

	public String getAddress() {
		return address;
	}

	public void setAddress(String address) {
		this.address = address;
	}

	@Override
	public boolean equals(Object o) {
		if (this == o) return true;
		if (o == null || getClass() != o.getClass()) return false;
		UserDTO userDTO = (UserDTO) o;
		return Objects.equals(email, userDTO.email) &&
			Objects.equals(password, userDTO.password) &&
			Objects.equals(name, userDTO.name) &&
			Objects.equals(phone, userDTO.phone) &&
			Objects.equals(address, userDTO.address);
	}

	@Override
	public int hashCode() {
		return Objects.hash(email, password, name, phone, address);
	}

	@Override
	public String toString() {
		return "UserDTO{" +
			"email='" + email + '\'' +
			", password='" + HIDDEN_PASSWORD + '\'' +
			", name='" + name + '\'' +
			", phone='" + phone + '\'' +
			", address='" + address + '\'' +
			'}';
	}
}

package market.service.impl;

import market.dao.DistilleryDAO;
import market.domain.Distillery;
import market.domain.Region;
import market.service.DistilleryService;
import market.service.RegionService;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.util.Comparator;
import java.util.List;
import java.util.Optional;
import java.util.stream.Collectors;

@Service
public class DistilleryServiceImpl implements DistilleryService {
	private final RegionService regionService;
	private final DistilleryDAO distilleryDAO;

	public DistilleryServiceImpl(RegionService regionService, DistilleryDAO distilleryDAO) {
		this.regionService = regionService;
		this.distilleryDAO = distilleryDAO;
	}

	@Transactional(readOnly = true)
	@Override
	public List<Distillery> findAll() {
		return distilleryDAO.findAll().stream()
			.sorted(Comparator.comparing(Distillery::getTitle))
			.collect(Collectors.toList());
	}

	@Transactional(readOnly = true)
	@Override
	public List<Distillery> findByRegion(Region region) {
		return distilleryDAO.findByRegionOrderByTitleAsc(region);
	}

	@Transactional(readOnly = true)
	@Override
	public Distillery findById(long distilleryId) {
		return distilleryDAO.findById(distilleryId).orElse(null);
	}

	@Transactional(readOnly = true)
	@Override
	public Distillery findByTitle(String title) {
		return distilleryDAO.findByTitle(title);
	}

	@Transactional
	@Override
	public void create(Distillery newDistillery, String regionName) {
		saveInternal(newDistillery, regionName);
	}

	@Override
	public void update(long distilleryId, Distillery changedDistillery, String regionName) {
		Optional<Distillery> originalDistillery = distilleryDAO.findById(distilleryId);
		if (originalDistillery.isPresent()) {
			changedDistillery.setId(originalDistillery.get().getId());
			saveInternal(changedDistillery, regionName);
		}
	}

	private void saveInternal(Distillery distillery, String regionName) {
		Region region = regionService.findByName(regionName);
		if (region != null) {
			distillery.setRegion(region);
			distilleryDAO.save(distillery);
		}
	}

	@Transactional
	@Override
	public void delete(long distilleryId) {
		distilleryDAO.deleteById(distilleryId);
	}
}

package com.alibaba.otter.canal.admin.model;

import java.io.Serializable;
import java.util.ArrayList;
import java.util.List;

public class Pager<T> implements Serializable {

    private static final long serialVersionUID = -986577815091763517L;

    private Long              count            = 0L;
    private List<T>           items            = new ArrayList<>();
    private Integer           page             = 1;
    private Integer           size             = 20;
    private Long              offset           = 0L;

    public Pager(){

    }

    public Pager(Integer page, Integer size){
        this.page = page;
        this.size = size;
    }

    public Pager(Long count, List<T> items){
        this.count = count;
        this.items = items;
    }

    public String toString() {
        return "PageResult[count=" + this.count + ", items=" + this.items + "]";
    }

    public Long getCount() {
        return this.count;
    }

    public void setCount(Long count) {
        this.count = count;
    }

    public List<T> getItems() {
        return items;
    }

    public void setItems(List<T> items) {
        this.items = items;
    }

    public Integer getPage() {
        if (page == null) {
            page = 1;
        }
        return page;
    }

    public void setPage(Integer page) {
        this.page = page;
    }

    public Integer getSize() {
        if (size == null) {
            size = 20;
        }
        return size;
    }

    public void setSize(Integer size) {
        this.size = size;
    }

    public Long getOffset() {
        offset = (long) (getPage() - 1) * (long) getSize();
        return offset;
    }

    public void setOffset(Long offset) {
        this.offset = offset;
    }
}

package com.alibaba.otter.canal.client.adapter;

import com.alibaba.otter.canal.client.adapter.support.Dml;
import com.alibaba.otter.canal.client.adapter.support.EtlResult;
import com.alibaba.otter.canal.client.adapter.support.OuterAdapterConfig;
import java.util.List;
import java.util.Map;
import java.util.Properties;

public class ProxyOuterAdapter implements OuterAdapter {

    private OuterAdapter outerAdapter;

    public ProxyOuterAdapter(OuterAdapter outerAdapter) {
        this.outerAdapter = outerAdapter;
    }

    private ClassLoader changeCL() {
        ClassLoader cl = Thread.currentThread().getContextClassLoader();
        Thread.currentThread().setContextClassLoader(outerAdapter.getClass().getClassLoader());
        return cl;
    }

    private void revertCL(ClassLoader cl) {
        Thread.currentThread().setContextClassLoader(cl);
    }

    @Override
    public void init(OuterAdapterConfig configuration, Properties envProperties) {
        ClassLoader cl = changeCL();
        try {
            outerAdapter.init(configuration, envProperties);
        } finally {
            revertCL(cl);
        }
    }

    @Override
    public void sync(List<Dml> dmls) {
        ClassLoader cl = changeCL();
        try {
            outerAdapter.sync(dmls);
        } finally {
            revertCL(cl);
        }
    }

    @Override
    public void destroy() {
        ClassLoader cl = changeCL();
        try {
            outerAdapter.destroy();
        } finally {
            revertCL(cl);
        }
    }

    @Override
    public EtlResult etl(String task, List<String> params) {
        ClassLoader cl = changeCL();
        try {
            return OuterAdapter.super.etl(task, params);
        } finally {
            revertCL(cl);
        }
    }

    @Override
    public Map<String, Object> count(String task) {
        ClassLoader cl = changeCL();
        try {
            return OuterAdapter.super.count(task);
        } finally {
            revertCL(cl);
        }
    }

    @Override
    public String getDestination(String task) {
        ClassLoader cl = changeCL();
        try {
            return OuterAdapter.super.getDestination(task);
        } finally {
            revertCL(cl);
        }
    }
}

