package net.bndy.wf.modules.cms.models;

import net.bndy.lib.StringHelper;
import net.bndy.wf.lib._BaseEntity;

import javax.persistence.*;
import java.util.List;

@Entity
@Table(name = "cms_channel")
public class Channel extends _BaseEntity {
	private static final long serialVersionUID = 1L;
	private String name;
    private String nameKey;
    private String path;
    @Enumerated(EnumType.ORDINAL)
    private BoType boType;
    private boolean isVisible;
    @Transient
    private boolean hasContent;
    @Transient
    private String url;
    @Transient
    private List<Channel> children;

    public String getName() {
        return name;
    }

    public void setName(String name) {
        this.name = name;
    }

    public String getNameKey() {
        return nameKey;
    }

    public void setNameKey(String nameKey) {
        this.nameKey = nameKey;
    }

    public String getPath() {
        return path;
    }

    public void setPath(String path) {
        this.path = path;
    }

    public BoType getBoType() {
        return boType;
    }

    public void setBoType(BoType boType) {
        this.boType = boType;
    }

    public boolean isVisible() {
        return isVisible;
    }

    public void setVisible(boolean visible) {
        isVisible = visible;
    }

    public boolean isHasContent() {
        return hasContent;
    }

    public void setHasContent(boolean hasContent) {
        this.hasContent = hasContent;
    }

    public void setUrl(String url) {
        this.url = url;
    }

    public String getUrl() {
        if (this.boType != null && (url == null || "".equals(url))) {
            switch (this.boType) {
                case Resource:
                    url = "/resources/" + (StringHelper.isNullOrWhiteSpace(this.nameKey) ? this.name : this.nameKey); // + "?id=" + this.id;
                    break;
                case Page:
                    url = "/page/"  + (StringHelper.isNullOrWhiteSpace(this.nameKey) ? this.name : this.nameKey); // + "?id=" + this.id;
                    break;
                case Article:
                    url = "/articles/"  + (StringHelper.isNullOrWhiteSpace(this.nameKey) ? this.name : this.nameKey); // + "?id=" + this.id;
                    break;
            }
        }
        return url == null ? "" : url;
    }

    public List<Channel> getChildren() {
        return children;
    }

    public void setChildren(List<Channel> children) {
        this.children = children;
    }

}

package com.yomahub.liteflow.spi.local;

import cn.hutool.core.collection.CollectionUtil;
import cn.hutool.core.io.FileUtil;
import cn.hutool.core.io.resource.ClassPathResource;
import cn.hutool.core.io.resource.FileResource;
import cn.hutool.core.io.resource.ResourceUtil;
import cn.hutool.core.util.ClassLoaderUtil;
import cn.hutool.core.util.StrUtil;
import com.yomahub.liteflow.exception.ConfigErrorException;
import com.yomahub.liteflow.spi.PathContentParser;
import com.yomahub.liteflow.util.PathMatchUtil;

import java.util.ArrayList;
import java.util.List;

public class LocalPathContentParser implements PathContentParser {

	private final static String FILE_URL_PREFIX = "file:";

	private final static String CLASSPATH_URL_PREFIX = "classpath:";

	@Override
	public List<String> parseContent(List<String> pathList) throws Exception {
		if (CollectionUtil.isEmpty(pathList)) {
			throw new ConfigErrorException("rule source must not be null");
		}
		List<String> absolutePathList = PathMatchUtil.searchAbsolutePath(pathList);

		List<String> contentList = new ArrayList<>();

		for (String path : absolutePathList) {
			if (FileUtil.isAbsolutePath(path) && FileUtil.isFile(path)) {
				path = FILE_URL_PREFIX + path;
			}
			else {
				if (!path.startsWith(CLASSPATH_URL_PREFIX)) {
					path = CLASSPATH_URL_PREFIX + path;
				}
			}
			String content = ResourceUtil.readUtf8Str(path);
			if (StrUtil.isNotBlank(content)) {
				contentList.add(content);
			}
		}

		return contentList;
	}

	@Override
	public List<String> getFileAbsolutePath(List<String> pathList) throws Exception {
		if (CollectionUtil.isEmpty(pathList)) {
			throw new ConfigErrorException("rule source must not be null");
		}
		List<String> absolutePathList = PathMatchUtil.searchAbsolutePath(pathList);
		List<String> result = new ArrayList<>();

		for (String path : absolutePathList) {
			if (FileUtil.isAbsolutePath(path) && FileUtil.isFile(path)) {
				path = FILE_URL_PREFIX + path;
				result.add(new FileResource(path).getFile().getAbsolutePath());
			}
			else {
				if (!path.startsWith(CLASSPATH_URL_PREFIX)) {
					path = CLASSPATH_URL_PREFIX + path;

					// 这里会有自定义解析器
					if (ClassLoaderUtil.isPresent(path)) {
						result.add(new ClassPathResource(path).getAbsolutePath());
					}
				}
			}
		}

		return result;
	}

	@Override
	public int priority() {
		return 2;
	}

}

