package org.hswebframework.web.context;

import lombok.SneakyThrows;
import reactor.core.publisher.Mono;
import reactor.util.context.Context;
import reactor.util.context.ContextView;

import java.io.Closeable;
import java.lang.reflect.UndeclaredThrowableException;
import java.util.Collections;
import java.util.Comparator;
import java.util.List;
import java.util.ServiceLoader;
import java.util.concurrent.Callable;
import java.util.function.Function;
import java.util.stream.Collectors;

public class ContextHolder {

    private static final List<ContextHolderSupport> supports;

    static {
        supports = ServiceLoader
            .load(ContextHolderSupport.class)
            .stream()
            .map(ServiceLoader.Provider::get)
            .collect(Collectors.toList());
        supports.add(new ThreadLocalContextHolderSupport());
        supports.sort(Comparator.comparingInt(ContextHolderSupport::order));
    }

    public static Closeable makeCurrent(ContextView context) {
        for (ContextHolderSupport support : supports) {
            if (support.isSupport()) {
                return support.makeCurrent(context);
            }
        }
        throw new UnsupportedOperationException();

    }

    @SneakyThrows
    public static <T> T doInContext(Context context, Callable<T> call) {
        try (Closeable ignore = makeCurrent(context)) {
            return call.call();
        } catch (UndeclaredThrowableException e) {
            throw e.getCause();
        }
    }

    public static <T> Mono<T> wrap(Function<ContextView, Mono<T>> handler) {
        return Mono.deferContextual(ctx -> {
            Context context = current().putAll(ctx);
            return handler.apply(context);
        });
    }

    public static Context current() {
        for (ContextHolderSupport support : supports) {
            if (support.isSupport()) {
                return support.current();
            }
        }
        throw new UnsupportedOperationException();
    }

    public interface ContextHolderSupport {
        boolean isSupport();

        Closeable makeCurrent(ContextView context);

        void clean();

        Context current();

        default int order() {
            return Integer.MIN_VALUE;
        }
    }

}

package org.hswebframework.web.datasource.switcher;

import lombok.extern.slf4j.Slf4j;
import org.hswebframework.web.context.ContextHolder;


import java.util.Deque;
import java.util.LinkedList;
import java.util.Optional;

@Slf4j
public class DefaultSwitcher implements Switcher {

    private String name;

    private String defaultId;

    private String type;

    public DefaultSwitcher(String name, String type) {
        this.name = "DefaultSwitcher.".concat(name);
        this.defaultId = name.concat(".").concat("_default");
        this.type = type;
    }

    protected Deque<String> getUsedHistoryQueue() {
        // 从ThreadLocal中获取一个使用记录
        return ContextHolder
            .current()
            .<Deque<String>>getOrEmpty(name)
            .orElseGet(LinkedList::new);
    }

    @Override
    public void useLast() {
        // 没有上一次了
        if (getUsedHistoryQueue().isEmpty()) {
            return;
        }
        //移除队尾,则当前的队尾则为上一次的数据源
        getUsedHistoryQueue().removeLast();
        if (log.isDebugEnabled()) {
            String current = current().orElse(null);
            if (null != current) {
                log.debug("try use last {} : {}", type, current);
            } else {
                log.debug("try use last default {}", type);
            }
        }
    }

    @Override
    public void use(String id) {
        //添加对队尾
        getUsedHistoryQueue().addLast(id);
        if (log.isDebugEnabled()) {
            log.debug("try use {} : {}", type, id);
        }
    }

    @Override
    public void useDefault() {
        getUsedHistoryQueue().addLast(defaultId);
        if (log.isDebugEnabled()) {
            log.debug("try use default {}", type);
        }
    }

    @Override
    public Optional<String> current() {
        if (getUsedHistoryQueue().isEmpty()) {
            return Optional.empty();
        }

        String activeId = getUsedHistoryQueue().getLast();
        if (defaultId.equals(activeId)) {
            return Optional.empty();
        }
        return Optional.of(activeId);
    }

    @Override
    public void reset() {
        getUsedHistoryQueue().clear();
        if (log.isDebugEnabled()) {
            log.debug("reset {} history", type);
        }
    }
}

